371     if (SignBit)
372       SignBit = !*SignBit;
373   }
374 
375   void fabs() {
376     if (KnownFPClasses & fcNegZero)
377       KnownFPClasses |= fcPosZero;
378 
379     if (KnownFPClasses & fcNegInf)
380       KnownFPClasses |= fcPosInf;
381 
382     if (KnownFPClasses & fcNegSubnormal)
383       KnownFPClasses |= fcPosSubnormal;
384 
385     if (KnownFPClasses & fcNegNormal)
386       KnownFPClasses |= fcPosNormal;
387 
388     signBitMustBeZero();
389   }
