391   /// Return true if the sign bit must be 0, ignoring the sign of nans.
392   bool signBitIsZeroOrNaN() const {
393     return isKnownNever(fcNegative);
394   }
395 
396   /// Assume the sign bit is zero.
397   void signBitMustBeZero() {
398     KnownFPClasses &= (fcPositive | fcNan);
399     SignBit = false;
400   }
401 
402   /// Assume the sign bit is one.
403   void signBitMustBeOne() {
404     KnownFPClasses &= (fcNegative | fcNan);
405     SignBit = true;
406   }
407 
408   void copysign(const KnownFPClass &Sign) {
409     // Don't know anything about the sign of the source. Expand the possible set
410     // to its opposite sign pair.
411     if (KnownFPClasses & fcZero)
412       KnownFPClasses |= fcZero;
413     if (KnownFPClasses & fcSubnormal)
414       KnownFPClasses |= fcSubnormal;
415     if (KnownFPClasses & fcNormal)
416       KnownFPClasses |= fcNormal;
417     if (KnownFPClasses & fcInf)
418       KnownFPClasses |= fcInf;
419 
420     // Sign bit is exactly preserved even for nans.
421     SignBit = Sign.SignBit;
422 
423     // Clear sign bits based on the input sign mask.
424     if (Sign.isKnownNever(fcPositive | fcNan) || (SignBit && *SignBit))
425       KnownFPClasses &= (fcNegative | fcNan);
426     if (Sign.isKnownNever(fcNegative | fcNan) || (SignBit && !*SignBit))
427       KnownFPClasses &= (fcPositive | fcNan);
428   }
429 
430   // Propagate knowledge that a non-NaN source implies the result can also not
431   // be a NaN. For unconstrained operations, signaling nans are not guaranteed
432   // to be quieted but cannot be introduced.
433   void propagateNaN(const KnownFPClass &Src, bool PreserveSign = false) {
434     if (Src.isKnownNever(fcNan)) {
435       knownNot(fcNan);
436       if (PreserveSign)
437         SignBit = Src.SignBit;
438     } else if (Src.isKnownNever(fcSNan))
439       knownNot(fcSNan);
440   }
